namespace sv_ddcbf024573e4ed7800a0d28a3021a72.Models;

public class WizardState
{
    // Step 1: Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = new();

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = new();

    public HashSet<int> CompletedSteps { get; set; } = new();
}

public class JobHistoryEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_ddcbf024573e4ed7800a0d28a3021a72.Models;

namespace sv_ddcbf024573e4ed7800a0d28a3021a72.Services;

/// <summary>
/// Singleton, in-memory store for wizard data keyed by a per-browser session cookie.
/// Both static-SSR layouts and interactive-server pages resolve the same instance,
/// so the progress bar and page content always see the same state.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
        => _states.GetOrAdd(sessionId, _ => new WizardState());
}

