    var currentStep = currentPath switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 0
    };

    var steps = new (int Number, string Label, string Href)[]
    {
        (1, "Personal Info", "/apply/personal-info"),
        (2, "Experience",    "/apply/experience"),
        (3, "References",    "/apply/references"),
        (4, "Review",        "/apply/review"),
    };
}

<div class="wizard-shell">
