+using sv_ddcbf024573e4ed7800a0d28a3021a72.Models;
+using sv_ddcbf024573e4ed7800a0d28a3021a72.Services;
+
+namespace sv_ddcbf024573e4ed7800a0d28a3021a72.Components.Pages.Apply;
+
+/// <summary>
+/// Base class that bridges the prerender → interactive boundary.
+/// During prerender, HttpContext is available so we read the session cookie.
+/// We persist the session ID via PersistentComponentState so the interactive
+/// circuit (where HttpContext is null) can pick it up.
+/// </summary>
+public abstract class WizardPageBase : ComponentBase, IDisposable
+{
+    [Inject] protected WizardStateStore StateStore { get; set; } = default!;
+    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
+    [Inject] protected NavigationManager Navigation { get; set; } = default!;
+    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
+
+    protected WizardState Wizard { get; private set; } = new();
+    private string _sessionId = "";
+    private PersistingComponentStateSubscription _sub;
+
+    protected override void OnInitialized()
+    {
+        _sub = PersistentState.RegisterOnPersisting(PersistState);
+
+        if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var id))
+        {
+            _sessionId = id!;
+        }
+        else
+        {
+            _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
+        }
+
+        if (!string.IsNullOrEmpty(_sessionId))
+        {
+            Wizard = StateStore.GetOrCreate(_sessionId);
+        }
+    }
+
+    private Task PersistState()
+    {
+        PersistentState.PersistAsJson("WizardSessionId", _sessionId);
+        return Task.CompletedTask;
+    }
+
+    public void Dispose() => _sub.Dispose();
+}
+

