@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase

<PageTitle>Personal Info</PageTitle>

<h4>Step 1 — Personal Information</h4>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private void Next()
    {
        Wizard.CompletedSteps.Add(1);
        Navigation.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase

<PageTitle>Experience</PageTitle>

<h4>Step 2 — Work Experience</h4>

@if (Wizard.JobHistory.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Duration</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var job in Wizard.JobHistory)
            {
                <tr>
                    <td>@job.Company</td>
                    <td>@job.Title</td>
                    <td>@job.Duration</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(job)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h6>Add Entry</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control form-control-sm" placeholder="Company" @bind="_company" />
        </div>
        <div class="col-md-4">
            <input class="form-control form-control-sm" placeholder="Job Title" @bind="_title" />
        </div>
        <div class="col-md-3">
            <input class="form-control form-control-sm" placeholder="Duration" @bind="_duration" />
        </div>
        <div class="col-md-1">
            <button class="btn btn-sm btn-success" @onclick="Add">+</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private string _company = "";
    private string _title = "";
    private string _duration = "";

    private void Add()
    {
        if (!string.IsNullOrWhiteSpace(_company))
        {
            Wizard.JobHistory.Add(new() { Company = _company, Title = _title, Duration = _duration });
            _company = _title = _duration = "";
        }
    }

    private void Remove(JobHistoryEntry entry) => Wizard.JobHistory.Remove(entry);

    private void Next()
    {
        Wizard.CompletedSteps.Add(2);
        Navigation.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase

<PageTitle>References</PageTitle>

<h4>Step 3 — References</h4>

@if (Wizard.References.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Name</th><th>Email</th><th>Relationship</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var r in Wizard.References)
            {
                <tr>
                    <td>@r.Name</td>
                    <td>@r.Email</td>
                    <td>@r.Relationship</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(r)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h6>Add Reference</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control form-control-sm" placeholder="Name" @bind="_name" />
        </div>
        <div class="col-md-4">
            <input class="form-control form-control-sm" placeholder="Email" @bind="_email" />
        </div>
        <div class="col-md-3">
            <input class="form-control form-control-sm" placeholder="Relationship" @bind="_relationship" />
        </div>
        <div class="col-md-1">
            <button class="btn btn-sm btn-success" @onclick="Add">+</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <a href="/apply/experience" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private string _name = "";
    private string _email = "";
    private string _relationship = "";

    private void Add()
    {
        if (!string.IsNullOrWhiteSpace(_name))
        {
            Wizard.References.Add(new() { Name = _name, Email = _email, Relationship = _relationship });
            _name = _email = _relationship = "";
        }
    }

    private void Remove(ReferenceContact r) => Wizard.References.Remove(r);

    private void Next()
    {
        Wizard.CompletedSteps.Add(3);
        Navigation.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardPageBase

<PageTitle>Review Application</PageTitle>

<h4>Step 4 — Review Your Application</h4>

<div class="card mb-3">
    <div class="card-header">Personal Information</div>
    <div class="card-body">
        <p><strong>Name:</strong> @Wizard.Name</p>
        <p><strong>Email:</strong> @Wizard.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header">Work Experience</div>
    <div class="card-body">
        @if (Wizard.JobHistory.Count == 0)
        {
            <p class="text-muted">No entries added.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Company</th><th>Title</th><th>Duration</th></tr></thead>
                <tbody>
                    @foreach (var job in Wizard.JobHistory)
                    {
                        <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Duration</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header">References</div>
    <div class="card-body">
        @if (Wizard.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
                <tbody>
                    @foreach (var r in Wizard.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <a href="/apply/references" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private bool _submitted;

    private void Submit()
    {
        Wizard.CompletedSteps.Add(4);
        _submitted = true;
    }
}

